```{.r .cell-code}
set.seed(2024)
ggraph(as_tbl_graph(g_pa), layout = "fr") +
  geom_edge_link(
    aes(alpha = score),
    arrow = arrow(length = unit(1.5, "mm"), type = "closed"),
    end_cap = circle(2.5, "mm"),
    color = "grey50"
  ) +
  geom_node_point(
    aes(color = proficiency, size = igraph::degree(g_pa, mode = "in")),
    alpha = 0.9
  ) +
  scale_color_brewer(palette = "Set2") +
  scale_size_continuous(range = c(2, 8)) +
  scale_edge_alpha_continuous(range = c(0.2, 0.7)) +
  labs(
    title = "Peer Assessment Network",
    color = "Proficiency", size = "In-degree",
    edge_alpha = "Score"
  ) +
  theme_graph(base_family = "sans")
```

::: {.cell-output-display}
![Peer Assessment Network (Directed Graph)](16_ネットワーク分析_files/figure-html/sla-peer-assessment-plot-1.png){width=2100}
:::
:::


この図では、まず大きいノードが「多く評価される学習者」であることを押さえ、次に濃いエッジが「高い評価」を表すことを確認する。評価が特定の熟達度層に偏っているか、互恵的なやり取りが目立つかを見ると、単なる成績差だけでなく社会的な評価構造も把握しやすい。


::: {.cell}

```{.r .cell-code}
# 受けた評価の平均スコアとライティング事前得点の関連
m_pa <- lm(mean_score_received ~ scale(writing_pre) + scale(indegree) + proficiency,
           data = pa_stats)
broom::tidy(m_pa, conf.int = TRUE) |>
  gt::gt() |>
  tab_header(title = "OLS: Peer Assessment Network → Mean Score Received") |>
  fmt_number(columns = where(is.numeric), decimals = 3)
```

